/* CISSP :: content/quiz2.js — CISSP Domain 2 question bank (100 items). */
window.CISSP = window.CISSP || {}; CISSP.questions = CISSP.questions || [];
CISSP.questions.push(
{ id:"D2-001", domain:2, obj:"2.1", diff:"easy", q:"An organization is beginning an information classification program. What is the PRIMARY reason to classify information assets?", options:["To apply protection commensurate with the asset's value and sensitivity","To reduce the total amount of stored data","To satisfy the auditors during the annual review","To eliminate the need for access controls"], answer:0, explain:"<strong>To apply protection commensurate with the asset's value and sensitivity</strong> — classification lets the organization match the strength and cost of controls to how much harm disclosure, alteration, or loss of the asset would cause, avoiding both over- and under-protection.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To reduce the total amount of stored data</b>: reducing volume is data minimization or retention management, not the purpose of classification.</span><span class='qd'><b>To satisfy the auditors during the annual review</b>: audit readiness is a side benefit, not the primary driver, which is proportional protection.</span><span class='qd'><b>To eliminate the need for access controls</b>: classification informs and strengthens access controls; it never removes the need for them.</span>" },
{ id:"D2-002", domain:2, obj:"2.1", diff:"easy", q:"Which party in a commercial organization holds the ultimate responsibility for assigning a classification level to an information asset?", options:["The data custodian","The data owner","The end user","The security administrator"], answer:1, explain:"<strong>The data owner</strong> — the owner is the business leader accountable for the asset and therefore decides its classification, acceptable use, and who may access it.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The data custodian</b>: the custodian implements and maintains the controls the owner specifies but does not set classification.</span><span class='qd'><b>The end user</b>: users must follow handling rules for the classification but have no authority to assign it.</span><span class='qd'><b>The security administrator</b>: administrators enforce technical controls; classification is a business decision reserved for the owner.</span>" },
{ id:"D2-003", domain:2, obj:"2.1", diff:"medium", q:"A government agency uses the labels Top Secret, Secret, Confidential, and Unclassified. What is the defining criterion that separates these levels?", options:["The storage cost of the data","The age of the records","The degree of damage to national security if the data were disclosed","The number of users who can access them"], answer:2, explain:"<strong>The degree of damage to national security if the data were disclosed</strong> — the U.S. government classification hierarchy is defined by the level of harm (exceptionally grave, serious, or measurable damage) expected from unauthorized disclosure.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The storage cost of the data</b>: cost of storage plays no part in national-security classification decisions.</span><span class='qd'><b>The age of the records</b>: age can trigger declassification review but does not define the level itself.</span><span class='qd'><b>The number of users who can access them</b>: user counts follow from classification and need-to-know, not the reverse.</span>" },
{ id:"D2-004", domain:2, obj:"2.1", diff:"medium", q:"A private company wants a classification scheme. Which set of labels is MOST typical of a commercial (non-government) classification model?", options:["Top Secret, Secret, Confidential, Unclassified","Level 1, Level 2, Level 3, Level 4","Red, Amber, Green, White","Confidential, Private, Sensitive, Public"], answer:3, explain:"<strong>Confidential, Private, Sensitive, Public</strong> — commercial schemes commonly use business-oriented tiers such as confidential/proprietary, private, sensitive, and public rather than military terminology.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Top Secret, Secret, Confidential, Unclassified</b>: these are the U.S. government/military levels tied to national-security damage, not a commercial model.</span><span class='qd'><b>Level 1, Level 2, Level 3, Level 4</b>: numbered tiers are ambiguous and not a standard named commercial scheme.</span><span class='qd'><b>Red, Amber, Green, White</b>: this resembles the Traffic Light Protocol for sharing, not a data classification hierarchy.</span>" },
{ id:"D2-005", domain:2, obj:"2.1", diff:"medium", q:"An organization has never inventoried its data. Before it can classify anything, which activity must occur FIRST?", options:["Identify and inventory the information assets it holds","Encrypt all databases","Purchase a DLP solution","Assign retention periods"], answer:0, explain:"<strong>Identify and inventory the information assets it holds</strong> — you cannot classify or protect what you have not discovered and cataloged, so asset identification and inventory precede classification.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Encrypt all databases</b>: blanket encryption without knowing what data exists is premature and may waste effort on low-value data.</span><span class='qd'><b>Purchase a DLP solution</b>: buying tooling before understanding the data leads to poorly tuned controls and gaps.</span><span class='qd'><b>Assign retention periods</b>: retention cannot be set sensibly until assets are identified and classified.</span>" },
{ id:"D2-006", domain:2, obj:"2.1", diff:"easy", q:"What does the term 'data sensitivity' primarily describe?", options:["How quickly data can be retrieved","The potential harm from unauthorized disclosure of the data","The physical size of the dataset","The encryption algorithm applied"], answer:1, explain:"<strong>The potential harm from unauthorized disclosure of the data</strong> — sensitivity measures the impact if confidentiality is lost, which is what drives classification and handling requirements.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>How quickly data can be retrieved</b>: retrieval speed is a performance/availability concern, not sensitivity.</span><span class='qd'><b>The physical size of the dataset</b>: size is unrelated to how damaging disclosure would be.</span><span class='qd'><b>The encryption algorithm applied</b>: an algorithm is a control choice, not a measure of sensitivity.</span>" },
{ id:"D2-007", domain:2, obj:"2.1", diff:"medium", q:"A manager argues that classifying data with too many levels is counterproductive. What is the BEST guidance on the number of classification levels?", options:["Use as many levels as there are departments","Always use exactly ten levels","Use the fewest levels that still allow meaningful, distinct handling requirements","Levels should match the number of employees"], answer:2, explain:"<strong>Use the fewest levels that still allow meaningful, distinct handling requirements</strong> — too many tiers create confusion and inconsistent handling, so a lean scheme with clearly differentiated protection rules is preferred.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Use as many levels as there are departments</b>: tying levels to org structure produces excessive, overlapping tiers that dilute clarity.</span><span class='qd'><b>Always use exactly ten levels</b>: there is no fixed magic number; the count should fit the organization's actual needs.</span><span class='qd'><b>Levels should match the number of employees</b>: headcount has no bearing on how many sensitivity tiers are appropriate.</span>" },
{ id:"D2-008", domain:2, obj:"2.1", diff:"hard", q:"A single dataset contains both public marketing text and embedded customer PII. Which principle governs the classification level that must be applied to the combined dataset?", options:["Classify at the level of the least sensitive element present","Average the sensitivity of all elements","Leave it unclassified because it is mixed","Classify at the level of the most sensitive element present"], answer:3, explain:"<strong>Classify at the level of the most sensitive element present</strong> — an aggregate or mixed container inherits the highest sensitivity of any data it holds, so the PII drives the classification of the whole dataset.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Classify at the level of the least sensitive element present</b>: this would under-protect the PII and expose the organization.</span><span class='qd'><b>Average the sensitivity of all elements</b>: averaging can leave highly sensitive data inadequately protected.</span><span class='qd'><b>Leave it unclassified because it is mixed</b>: mixed content is precisely when highest-level classification must apply.</span>" },
{ id:"D2-009", domain:2, obj:"2.1", diff:"hard", q:"A large volume of individually low-sensitivity records, when combined, could reveal strategic patterns useful to a competitor. Which concept explains why the combined set may warrant a higher classification?", options:["The aggregation problem","Data remanence","Data normalization","Steganography"], answer:0, explain:"<strong>The aggregation problem</strong> — combining many low-value items can produce a whole that is far more sensitive than any single element, justifying a higher classification for the aggregate.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Data remanence</b>: remanence is residual data left on media after deletion, unrelated to combining records.</span><span class='qd'><b>Data normalization</b>: normalization is a database design technique to reduce redundancy, not a sensitivity concept.</span><span class='qd'><b>Steganography</b>: steganography hides data within other data and does not describe cumulative sensitivity.</span>" },
{ id:"D2-010", domain:2, obj:"2.1", diff:"medium", q:"An organization must decide who assigns value to information assets for classification. Which statement BEST reflects CISSP guidance on asset valuation?", options:["Value is set solely by the IT department","Value should reflect the asset's importance to the business and the impact of its loss","Only tangible replacement cost matters","All data has equal value"], answer:1, explain:"<strong>Value should reflect the asset's importance to the business and the impact of its loss</strong> — valuation considers both quantitative and qualitative business impact, driving proportional protection and classification decisions.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Value is set solely by the IT department</b>: business owners, not IT alone, understand the asset's importance and impact.</span><span class='qd'><b>Only tangible replacement cost matters</b>: intangible losses such as reputation and competitive harm often exceed replacement cost.</span><span class='qd'><b>All data has equal value</b>: treating all data equally defeats the purpose of classification and misallocates resources.</span>" },
{ id:"D2-011", domain:2, obj:"2.1", diff:"easy", q:"Which of the following is an example of an intangible asset that should be considered in asset identification?", options:["A rack of servers","A shipment of laptops","The organization's brand reputation","A backup tape library"], answer:2, explain:"<strong>The organization's brand reputation</strong> — reputation, goodwill, and intellectual property are intangible assets whose loss can be highly damaging even though they have no physical form.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A rack of servers</b>: servers are tangible physical hardware assets.</span><span class='qd'><b>A shipment of laptops</b>: laptops are tangible equipment, not intangible.</span><span class='qd'><b>A backup tape library</b>: tapes are physical media, a tangible asset.</span>" },
{ id:"D2-012", domain:2, obj:"2.1", diff:"medium", q:"A CISO wants classification decisions to be defensible and consistent. Which document should define how each level is determined and handled?", options:["A firewall ruleset","A vendor contract","The incident response runbook","A data classification policy"], answer:3, explain:"<strong>A data classification policy</strong> — a formal policy defines the levels, the criteria for assigning them, and the handling requirements for each, giving the program consistency and defensibility.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A firewall ruleset</b>: a ruleset enforces network controls but does not define classification criteria.</span><span class='qd'><b>A vendor contract</b>: contracts govern third-party obligations, not the internal classification scheme.</span><span class='qd'><b>The incident response runbook</b>: runbooks address handling incidents, not defining classification levels.</span>" },
{ id:"D2-013", domain:2, obj:"2.1", diff:"medium", q:"Data that, if disclosed, would violate privacy law but would not harm national security is BEST described in a commercial scheme as which category?", options:["Private/PII","Public","Top Secret","Unclassified"], answer:0, explain:"<strong>Private/PII</strong> — personal information protected by privacy laws such as GDPR or HIPAA falls into the private/sensitive tier of a commercial scheme, distinct from public data.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Public</b>: public data can be freely disclosed and by definition is not privacy-protected.</span><span class='qd'><b>Top Secret</b>: Top Secret is a government national-security label, not a commercial privacy category.</span><span class='qd'><b>Unclassified</b>: unclassified is a government term for data needing no protection level.</span>" },
{ id:"D2-014", domain:2, obj:"2.1", diff:"hard", q:"A business unit insists all its data be marked 'Confidential' to be safe. What is the PRIMARY risk of systematically over-classifying data?", options:["It improves security with no downside","It raises handling costs and can cause users to ignore classifications","It automatically reduces retention obligations","It eliminates the need for encryption"], answer:1, explain:"<strong>It raises handling costs and can cause users to ignore classifications</strong> — over-classification wastes resources on excessive controls and erodes the credibility of labels, leading staff to disregard them and undermining the whole scheme.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It improves security with no downside</b>: over-classification carries real costs and behavioral risks, so there is a downside.</span><span class='qd'><b>It automatically reduces retention obligations</b>: classification level does not by itself change legal retention requirements.</span><span class='qd'><b>It eliminates the need for encryption</b>: labeling data confidential does not remove the need for protective controls.</span>" },
{ id:"D2-015", domain:2, obj:"2.1", diff:"easy", q:"Which activity is the FIRST step in building an accurate asset inventory?", options:["Assigning classifications","Setting retention schedules","Discovering and enumerating assets across the environment","Encrypting the assets"], answer:2, explain:"<strong>Discovering and enumerating assets across the environment</strong> — you must find and list assets, including shadow IT and forgotten data stores, before you can classify, protect, or retire them.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Assigning classifications</b>: classification requires knowing the assets first, so discovery must precede it.</span><span class='qd'><b>Setting retention schedules</b>: retention depends on knowing what data exists and its classification.</span><span class='qd'><b>Encrypting the assets</b>: you cannot protect assets you have not yet discovered.</span>" },
{ id:"D2-016", domain:2, obj:"2.1", diff:"medium", q:"An organization treats software licenses, source code, and patents as assets requiring protection. Which asset category do these represent?", options:["Physical assets","Consumables","Network infrastructure","Intellectual property"], answer:3, explain:"<strong>Intellectual property</strong> — source code, patents, trademarks, and proprietary designs are intellectual-property assets whose confidentiality and integrity carry significant business value.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Physical assets</b>: physical assets are tangible items like hardware and facilities, not IP.</span><span class='qd'><b>Consumables</b>: consumables are expendable supplies, not protected intellectual property.</span><span class='qd'><b>Network infrastructure</b>: infrastructure is the equipment carrying data, distinct from the IP itself.</span>" },
{ id:"D2-017", domain:2, obj:"2.1", diff:"medium", q:"A classification review finds that a dataset's sensitivity has dropped over time. What is the appropriate action?", options:["Reclassify (downgrade) the data through a controlled process","Leave the classification unchanged permanently","Immediately delete the data","Encrypt it more strongly"], answer:0, explain:"<strong>Reclassify (downgrade) the data through a controlled process</strong> — classification is not permanent; when sensitivity changes, the owner should formally reclassify so controls stay proportional to current risk.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Leave the classification unchanged permanently</b>: static labels lead to over-protecting data that no longer warrants it.</span><span class='qd'><b>Immediately delete the data</b>: lowered sensitivity does not imply the data should be destroyed; retention rules still apply.</span><span class='qd'><b>Encrypt it more strongly</b>: adding controls to less-sensitive data is the opposite of the proportional response needed.</span>" },
{ id:"D2-018", domain:2, obj:"2.1", diff:"medium", q:"Who should approve any change to an information asset's classification level?", options:["Any user with access","The data owner responsible for that asset","The help desk","The external auditor"], answer:1, explain:"<strong>The data owner responsible for that asset</strong> — because the owner is accountable for the asset's protection, only the owner has authority to approve reclassification decisions.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Any user with access</b>: access does not confer authority to change classification.</span><span class='qd'><b>The help desk</b>: the help desk provides support but does not own or govern asset classification.</span><span class='qd'><b>The external auditor</b>: auditors assess controls; they do not set or change classifications.</span>" },
{ id:"D2-019", domain:2, obj:"2.1", diff:"hard", q:"An enterprise wants classification to be applied consistently at scale across millions of files. Which approach BEST supports this while reducing human error?", options:["Rely entirely on each user's judgment","Classify only new files and ignore legacy data","Combine clear policy criteria with automated data discovery and classification tooling","Use a single 'Confidential' label for everything"], answer:2, explain:"<strong>Combine clear policy criteria with automated data discovery and classification tooling</strong> — automation enforces the policy's criteria consistently at scale, catching content manual review would miss while still reflecting owner-defined rules.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Rely entirely on each user's judgment</b>: purely manual classification is inconsistent and does not scale to millions of files.</span><span class='qd'><b>Classify only new files and ignore legacy data</b>: leaving legacy data unclassified creates large unprotected risk pools.</span><span class='qd'><b>Use a single 'Confidential' label for everything</b>: blanket labeling is over-classification that erodes trust in the scheme.</span>" },
{ id:"D2-020", domain:2, obj:"2.1", diff:"easy", q:"Which of the following BEST distinguishes an 'asset' from ordinary 'data' in asset security?", options:["Assets are always hardware and data is always software","Data cannot be an asset","Only encrypted data counts as an asset","An asset is anything of value to the organization that warrants protection, which includes data"], answer:3, explain:"<strong>An asset is anything of value to the organization that warrants protection, which includes data</strong> — assets encompass hardware, software, people, facilities, and information; data is one important class of asset.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Assets are always hardware and data is always software</b>: this is a false dichotomy; assets span many categories.</span><span class='qd'><b>Data cannot be an asset</b>: data is frequently the most valuable asset an organization holds.</span><span class='qd'><b>Only encrypted data counts as an asset</b>: an asset's value is independent of whether it is encrypted.</span>" },
{ id:"D2-021", domain:2, obj:"2.2", diff:"easy", q:"What is the PRIMARY purpose of labeling classified media and documents?", options:["To communicate the required handling and protection level to anyone who encounters them","To make them look official","To increase storage efficiency","To satisfy marketing requirements"], answer:0, explain:"<strong>To communicate the required handling and protection level to anyone who encounters them</strong> — labels tell users how the asset must be stored, transmitted, shared, and destroyed, ensuring consistent handling.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To make them look official</b>: appearance is irrelevant; labels convey handling requirements.</span><span class='qd'><b>To increase storage efficiency</b>: labeling has no effect on storage efficiency.</span><span class='qd'><b>To satisfy marketing requirements</b>: labeling is a security control, unrelated to marketing.</span>" },
{ id:"D2-022", domain:2, obj:"2.2", diff:"medium", q:"In asset security terminology, what is the distinction between 'marking' and 'labeling'?", options:["They are identical with no difference","Marking is the human-readable designation of sensitivity; labeling often refers to machine-readable or physical tags used to enforce handling","Marking applies only to hardware","Labeling applies only to network traffic"], answer:1, explain:"<strong>Marking is the human-readable designation of sensitivity; labeling often refers to machine-readable or physical tags used to enforce handling</strong> — marking makes the classification visible to people, while labels (metadata, tags, media stickers) can drive automated or physical handling.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>They are identical with no difference</b>: the two terms have distinct connotations of human-visible versus machine/physical designation.</span><span class='qd'><b>Marking applies only to hardware</b>: marking applies to documents, media, and data, not solely hardware.</span><span class='qd'><b>Labeling applies only to network traffic</b>: labeling is far broader than network traffic.</span>" },
{ id:"D2-023", domain:2, obj:"2.2", diff:"medium", q:"A confidential report is printed. Where should its classification marking appear?", options:["Only on the first page","Only in the file's metadata","On the top and bottom of every page and the cover","Nowhere, to avoid drawing attention"], answer:2, explain:"<strong>On the top and bottom of every page and the cover</strong> — marking every page (typically header and footer) ensures the classification remains clear even if pages are separated or copied.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Only on the first page</b>: separated pages would lose their classification if only page one is marked.</span><span class='qd'><b>Only in the file's metadata</b>: a printed page has no accessible metadata, so a physical marking is required.</span><span class='qd'><b>Nowhere, to avoid drawing attention</b>: security-through-obscurity leaves handlers unaware of required protections.</span>" },
{ id:"D2-024", domain:2, obj:"2.2", diff:"medium", q:"An organization stores classification information as embedded metadata that DLP tools can read. This machine-readable designation is BEST called what?", options:["A watermark","A firewall tag","A retention schedule","A security label"], answer:3, explain:"<strong>A security label</strong> — a security label is machine-readable metadata bound to the object that expresses its classification so automated controls like DLP can enforce handling.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A watermark</b>: a watermark is a visible or hidden mark for provenance/tracing, not a control-enforcing classification label.</span><span class='qd'><b>A firewall tag</b>: firewall tags relate to network policy, not object classification metadata.</span><span class='qd'><b>A retention schedule</b>: a retention schedule governs how long data is kept, not its sensitivity label.</span>" },
{ id:"D2-025", domain:2, obj:"2.2", diff:"easy", q:"Backup tapes leaving a facility for offsite storage should be handled according to which of the following?", options:["The handling requirements of their highest-classified contents","Whatever is convenient for the courier","Only the physical weight of the tapes","The color of the tape cartridge"], answer:0, explain:"<strong>The handling requirements of their highest-classified contents</strong> — media inherits the handling and marking rules of the most sensitive data it contains, so transport, encryption, and chain-of-custody follow that level.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Whatever is convenient for the courier</b>: convenience cannot override defined handling requirements.</span><span class='qd'><b>Only the physical weight of the tapes</b>: weight is irrelevant to information handling controls.</span><span class='qd'><b>The color of the tape cartridge</b>: cartridge color is not a handling determinant.</span>" },
{ id:"D2-026", domain:2, obj:"2.2", diff:"medium", q:"A courier transports Secret documents between two sites. Which handling requirement is MOST directly addressed by requiring signatures at each transfer point?", options:["Data at rest encryption","Chain of custody","Data classification","Network segmentation"], answer:1, explain:"<strong>Chain of custody</strong> — signed transfers create an unbroken, documented record of who possessed the material at each point, which is central to handling sensitive media in transit.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Data at rest encryption</b>: encryption protects stored data but does not document custody handoffs.</span><span class='qd'><b>Data classification</b>: classification sets the level; signatures address custody, not the label itself.</span><span class='qd'><b>Network segmentation</b>: segmentation is a network control unrelated to physical transport of documents.</span>" },
{ id:"D2-027", domain:2, obj:"2.2", diff:"hard", q:"An analyst emails a spreadsheet marked Confidential to an external partner without encryption. Which handling failure occurred?", options:["Improper classification","A marking error","A handling/transmission control failure for the data's classification","A retention violation"], answer:2, explain:"<strong>A handling/transmission control failure for the data's classification</strong> — the data was correctly marked, but the required protection for transmitting Confidential data (encryption, approved channel) was not applied, breaching handling requirements.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Improper classification</b>: the data was properly classified as Confidential; classification was not the failure.</span><span class='qd'><b>A marking error</b>: the marking was present and correct, so marking was not the issue.</span><span class='qd'><b>A retention violation</b>: retention concerns how long data is kept, not how it is transmitted.</span>" },
{ id:"D2-028", domain:2, obj:"2.2", diff:"medium", q:"Why should classification markings persist when a document is copied, exported to another format, or excerpted?", options:["To increase file size","To disable printing","To speed up searches","To ensure the derived copy retains the same handling obligations"], answer:3, explain:"<strong>To ensure the derived copy retains the same handling obligations</strong> — derivative works inherit the sensitivity of their source, so markings must carry over to keep protection consistent across copies and formats.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To increase file size</b>: persistent markings are about control continuity, not file size.</span><span class='qd'><b>To disable printing</b>: markings communicate handling; they do not by themselves block printing.</span><span class='qd'><b>To speed up searches</b>: markings are not a search-optimization mechanism.</span>" },
{ id:"D2-029", domain:2, obj:"2.2", diff:"easy", q:"Which of the following is the BEST example of a physical label supporting asset handling?", options:["A barcode/asset tag on a laptop identifying its owner and classification","A firewall rule","A password policy","A DNS record"], answer:0, explain:"<strong>A barcode/asset tag on a laptop identifying its owner and classification</strong> — a physical asset tag ties the device to inventory records and communicates handling requirements, a concrete labeling control.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A firewall rule</b>: a firewall rule is a logical network control, not a physical label.</span><span class='qd'><b>A password policy</b>: a password policy is an access control, not a handling label.</span><span class='qd'><b>A DNS record</b>: a DNS record maps names to addresses and is not an asset label.</span>" },
{ id:"D2-030", domain:2, obj:"2.2", diff:"medium", q:"An organization wants markings that machines can enforce and humans can read. What is the BEST practice?", options:["Use only hidden metadata","Apply both human-readable markings and machine-readable labels","Use only verbal instructions","Avoid markings to reduce clutter"], answer:1, explain:"<strong>Apply both human-readable markings and machine-readable labels</strong> — pairing visible markings for people with embedded labels for tools ensures consistent handling by both humans and automated controls.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Use only hidden metadata</b>: hidden-only labels leave humans unaware of handling requirements.</span><span class='qd'><b>Use only verbal instructions</b>: verbal instructions are not durable and do not travel with the asset.</span><span class='qd'><b>Avoid markings to reduce clutter</b>: omitting markings undermines consistent handling entirely.</span>" },
{ id:"D2-031", domain:2, obj:"2.2", diff:"hard", q:"A file's embedded classification label says 'Public' but its content clearly includes customer Social Security numbers. According to sound handling practice, what should occur?", options:["Trust the label and treat it as Public","Delete the file immediately without review","Investigate and correct the mislabel, treating the content as its true higher sensitivity until resolved","Ignore the discrepancy"], answer:2, explain:"<strong>Investigate and correct the mislabel, treating the content as its true higher sensitivity until resolved</strong> — content trumps an erroneous label; the safest course is to protect at the higher level and fix the classification through the owner.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Trust the label and treat it as Public</b>: blindly trusting a demonstrably wrong label would expose PII.</span><span class='qd'><b>Delete the file immediately without review</b>: deletion may destroy needed data and bypasses proper reclassification.</span><span class='qd'><b>Ignore the discrepancy</b>: ignoring a mislabel leaves sensitive data unprotected.</span>" },
{ id:"D2-032", domain:2, obj:"2.2", diff:"medium", q:"When declassifying a document, which marking action is required?", options:["No change is needed","Add more restrictive markings","Shred the document","Update or remove the old markings and record the declassification authority and date"], answer:3, explain:"<strong>Update or remove the old markings and record the declassification authority and date</strong> — declassification must be documented and the markings revised so handlers apply the correct, lower protection level.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>No change is needed</b>: stale higher markings would cause unnecessary over-protection and confusion.</span><span class='qd'><b>Add more restrictive markings</b>: declassification lowers sensitivity, so more restrictive markings are wrong.</span><span class='qd'><b>Shred the document</b>: declassification does not imply destruction; retention rules may still require keeping it.</span>" },
{ id:"D2-033", domain:2, obj:"2.2", diff:"easy", q:"Which handling requirement is MOST associated with the highest classification levels?", options:["Restrict access strictly on a need-to-know basis with strong controls","Store on any shared drive","Print freely without markings","Email in plaintext"], answer:0, explain:"<strong>Restrict access strictly on a need-to-know basis with strong controls</strong> — higher classifications demand tighter access limitation, encryption, and auditing to match the greater harm from disclosure.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Store on any shared drive</b>: unrestricted storage violates the confinement highly sensitive data requires.</span><span class='qd'><b>Print freely without markings</b>: uncontrolled printing and missing markings breach handling rules.</span><span class='qd'><b>Email in plaintext</b>: plaintext email is an insecure channel unsuitable for sensitive data.</span>" },
{ id:"D2-034", domain:2, obj:"2.2", diff:"medium", q:"An organization adopts the Traffic Light Protocol (TLP) for shared threat intelligence. What does TLP primarily govern?", options:["The encryption strength of files","How widely a piece of shared information may be redistributed","The retention period of logs","The classification of hardware assets"], answer:1, explain:"<strong>How widely a piece of shared information may be redistributed</strong> — TLP labels (RED, AMBER, GREEN, CLEAR) tell recipients the permitted audience for onward sharing, a handling/marking convention for shared intelligence.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The encryption strength of files</b>: TLP addresses distribution scope, not cryptographic strength.</span><span class='qd'><b>The retention period of logs</b>: TLP does not define retention.</span><span class='qd'><b>The classification of hardware assets</b>: TLP is about information sharing, not hardware classification.</span>" },
{ id:"D2-035", domain:2, obj:"2.6", diff:"hard", q:"A manager must decide handling rules for a new 'Restricted' tier between Internal and Confidential. Which factor should MOST drive the specific handling requirements assigned to it?", options:["The alphabetical order of the label","The preferences of the IT team","The impact of unauthorized disclosure and the controls needed to mitigate it","The number of files currently in that tier"], answer:2, explain:"<strong>The impact of unauthorized disclosure and the controls needed to mitigate it</strong> — handling requirements for any tier flow from the harm expected if the data is exposed, ensuring proportional protection.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The alphabetical order of the label</b>: naming order has no bearing on required protection.</span><span class='qd'><b>The preferences of the IT team</b>: preferences do not determine risk-based handling needs.</span><span class='qd'><b>The number of files currently in that tier</b>: volume does not set the protection level; impact does.</span>" },
{ id:"D2-036", domain:2, obj:"2.3", diff:"easy", q:"What is the PRIMARY purpose of maintaining an accurate asset inventory?", options:["To increase the IT budget","To slow down provisioning","To avoid documentation","To know what must be protected, patched, tracked, and eventually retired"], answer:3, explain:"<strong>To know what must be protected, patched, tracked, and eventually retired</strong> — you can only secure and manage assets you know exist; the inventory underpins vulnerability management, licensing, and lifecycle control.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To increase the IT budget</b>: an inventory informs budgeting but its purpose is asset management, not spending.</span><span class='qd'><b>To slow down provisioning</b>: a good inventory streamlines, not slows, provisioning.</span><span class='qd'><b>To avoid documentation</b>: the inventory is documentation; the goal is visibility and control.</span>" },
{ id:"D2-037", domain:2, obj:"2.3", diff:"medium", q:"During onboarding, a new server is deployed from a hardened, approved image with only required services enabled. This practice is BEST described as what?", options:["Secure provisioning via a baseline configuration","Data classification","Media sanitization","Penetration testing"], answer:0, explain:"<strong>Secure provisioning via a baseline configuration</strong> — building from a hardened standard image with minimal services enforces a secure baseline and reduces the attack surface from day one.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Data classification</b>: classification labels information sensitivity; it is not about building a secure server image.</span><span class='qd'><b>Media sanitization</b>: sanitization is an end-of-life process, not provisioning.</span><span class='qd'><b>Penetration testing</b>: pen testing evaluates security; it does not provision the asset.</span>" },
{ id:"D2-038", domain:2, obj:"2.3", diff:"medium", q:"An auditor finds several servers running in production that appear in no inventory or CMDB. What risk does this 'shadow IT' create?", options:["Improved visibility","Unmanaged assets that are unpatched, unmonitored, and outside security controls","Lower attack surface","Automatic compliance"], answer:1, explain:"<strong>Unmanaged assets that are unpatched, unmonitored, and outside security controls</strong> — assets absent from inventory escape patching, monitoring, and hardening, becoming prime targets and blind spots.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Improved visibility</b>: undocumented assets reduce, not improve, visibility.</span><span class='qd'><b>Lower attack surface</b>: unmanaged systems increase the attack surface.</span><span class='qd'><b>Automatic compliance</b>: assets outside inventory typically break, not ensure, compliance.</span>" },
{ id:"D2-039", domain:2, obj:"2.3", diff:"medium", q:"Which repository is specifically designed to track configuration items and their relationships across the asset lifecycle?", options:["A DNS zone file","A password vault","A configuration management database (CMDB)","A firewall log"], answer:2, explain:"<strong>A configuration management database (CMDB)</strong> — a CMDB records configuration items, their attributes, and interdependencies, supporting provisioning, change, and lifecycle management.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A DNS zone file</b>: a zone file maps hostnames to addresses, not full asset configuration data.</span><span class='qd'><b>A password vault</b>: a vault stores credentials, not asset configuration relationships.</span><span class='qd'><b>A firewall log</b>: logs record traffic events, not the configuration-item catalog.</span>" },
{ id:"D2-040", domain:2, obj:"2.3", diff:"easy", q:"Which item is the MOST important to capture for each asset in an inventory to enable ownership-based decisions?", options:["The asset's paint color","The vendor's stock price","The office temperature","The assigned owner/custodian and classification of data it handles"], answer:3, explain:"<strong>The assigned owner/custodian and classification of data it handles</strong> — owner and data classification let the organization assign accountability and proportional controls, the core of asset governance.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The asset's paint color</b>: cosmetic attributes have no security relevance.</span><span class='qd'><b>The vendor's stock price</b>: financials of a vendor are irrelevant to asset handling.</span><span class='qd'><b>The office temperature</b>: environmental trivia does not drive asset security decisions.</span>" },
{ id:"D2-041", domain:2, obj:"2.3", diff:"hard", q:"A cloud team spins up hundreds of ephemeral containers daily. What is the BEST way to keep the asset inventory accurate in such a dynamic environment?", options:["Use automated discovery and tagging integrated with the orchestration and CMDB","Update a spreadsheet manually each morning","Stop using containers","Inventory only physical servers"], answer:0, explain:"<strong>Use automated discovery and tagging integrated with the orchestration and CMDB</strong> — dynamic, ephemeral assets require automated, continuous discovery and tagging so the inventory reflects reality in near real time.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Update a spreadsheet manually each morning</b>: manual tracking cannot keep pace with hundreds of daily ephemeral assets.</span><span class='qd'><b>Stop using containers</b>: abandoning a valid technology to ease inventory is not a proportional response.</span><span class='qd'><b>Inventory only physical servers</b>: ignoring cloud assets leaves the majority of the environment untracked.</span>" },
{ id:"D2-042", domain:2, obj:"2.3", diff:"medium", q:"Before a purchased used server is placed into service, which provisioning step BEST reduces the risk of inheriting prior data or configurations?", options:["Immediately connect it to production","Sanitize/re-image the system and apply the approved secure baseline","Leave the previous owner's accounts active","Skip patching to save time"], answer:1, explain:"<strong>Sanitize/re-image the system and apply the approved secure baseline</strong> — wiping and rebuilding from a trusted image removes any residual data, malware, or misconfiguration before the asset enters service.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Immediately connect it to production</b>: connecting an unvetted system risks importing malware or leftover data.</span><span class='qd'><b>Leave the previous owner's accounts active</b>: stale accounts are an access-control risk and must be removed.</span><span class='qd'><b>Skip patching to save time</b>: an unpatched system is exposed to known exploits from the start.</span>" },
{ id:"D2-043", domain:2, obj:"2.3", diff:"medium", q:"An asset's inventory record should be updated at which points in its lifecycle?", options:["Only at purchase","Only when it fails","At acquisition, deployment, changes, and decommissioning","Never after deployment"], answer:2, explain:"<strong>At acquisition, deployment, changes, and decommissioning</strong> — accurate inventory requires updates across the entire lifecycle so the record always reflects the asset's current state and status.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Only at purchase</b>: a record frozen at purchase quickly becomes inaccurate.</span><span class='qd'><b>Only when it fails</b>: waiting for failure leaves the inventory stale during normal operation.</span><span class='qd'><b>Never after deployment</b>: assets change; the inventory must track those changes.</span>" },
{ id:"D2-044", domain:2, obj:"2.3", diff:"hard", q:"A CISO wants provisioning to be repeatable and auditable so every system is deployed identically and securely. Which practice BEST achieves this?", options:["Manual, ad hoc server builds","Letting each admin choose settings","Disabling logging during builds","Infrastructure as code with version-controlled, hardened templates"], answer:3, explain:"<strong>Infrastructure as code with version-controlled, hardened templates</strong> — codifying builds makes provisioning repeatable, reviewable, and auditable, guaranteeing consistent secure baselines across systems.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Manual, ad hoc server builds</b>: manual builds drift and are hard to audit or reproduce.</span><span class='qd'><b>Letting each admin choose settings</b>: individual choices create inconsistent, unverifiable configurations.</span><span class='qd'><b>Disabling logging during builds</b>: removing logs destroys the auditability the CISO wants.</span>" },
{ id:"D2-045", domain:2, obj:"2.3", diff:"easy", q:"What is the BEST description of 'asset management' in the context of asset security?", options:["The processes for tracking, maintaining, and controlling assets throughout their lifecycle","Buying as many assets as possible","Only counting hardware once a year","Deleting all inventory records"], answer:0, explain:"<strong>The processes for tracking, maintaining, and controlling assets throughout their lifecycle</strong> — asset management covers acquisition, deployment, maintenance, and disposal so assets are governed and protected end to end.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Buying as many assets as possible</b>: acquisition volume is not the goal of asset management.</span><span class='qd'><b>Only counting hardware once a year</b>: a single annual count is far too limited for effective management.</span><span class='qd'><b>Deleting all inventory records</b>: destroying records eliminates the visibility asset management depends on.</span>" },
{ id:"D2-046", domain:2, obj:"2.3", diff:"medium", q:"A vulnerability scan can only assess systems that are known to the scanner. Which foundational control makes comprehensive scanning possible?", options:["A larger marketing budget","A complete and current asset inventory","Longer passwords","A faster internet connection"], answer:1, explain:"<strong>A complete and current asset inventory</strong> — scanning coverage depends on knowing every asset; gaps in inventory become unscanned, unmanaged exposure.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A larger marketing budget</b>: budget for marketing is unrelated to scan coverage.</span><span class='qd'><b>Longer passwords</b>: password length is an access control, not a scanning enabler.</span><span class='qd'><b>A faster internet connection</b>: bandwidth does not determine which assets are known to the scanner.</span>" },
{ id:"D2-047", domain:2, obj:"2.3", diff:"medium", q:"Which of the following BEST reflects the concept of 'least functionality' during secure provisioning?", options:["Enable every available feature by default","Grant all users administrator rights","Install and enable only the services and software required for the system's role","Open all firewall ports"], answer:2, explain:"<strong>Install and enable only the services and software required for the system's role</strong> — least functionality minimizes the attack surface by disabling or removing anything not needed for the asset's purpose.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Enable every available feature by default</b>: enabling everything maximizes attack surface, the opposite of least functionality.</span><span class='qd'><b>Grant all users administrator rights</b>: broad admin rights violate least privilege, a related but distinct principle wrongly applied here.</span><span class='qd'><b>Open all firewall ports</b>: opening all ports needlessly exposes services and increases risk.</span>" },
{ id:"D2-048", domain:2, obj:"2.3", diff:"hard", q:"A merger doubles the company's asset base overnight, and many acquired systems are undocumented. What is the FIRST priority to bring them under control?", options:["Decommission all acquired systems","Rebrand the acquired systems","Increase the marketing spend","Discover and inventory the acquired assets and their data classifications"], answer:3, explain:"<strong>Discover and inventory the acquired assets and their data classifications</strong> — you cannot secure, patch, or govern the new environment until you know what assets exist and what data they hold.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Decommission all acquired systems</b>: blanket decommissioning would destroy needed business capability before it is understood.</span><span class='qd'><b>Rebrand the acquired systems</b>: rebranding is cosmetic and does nothing to secure the assets.</span><span class='qd'><b>Increase the marketing spend</b>: marketing is irrelevant to securing newly acquired IT assets.</span>" },
{ id:"D2-049", domain:2, obj:"2.3", diff:"medium", q:"Why should decommissioned assets be formally removed from the inventory and their records archived rather than simply forgotten?", options:["To maintain accurate records, prove proper disposal, and avoid ghost assets skewing metrics","To inflate the asset count","To make the inventory harder to read","To increase license costs"], answer:0, explain:"<strong>To maintain accurate records, prove proper disposal, and avoid ghost assets skewing metrics</strong> — formal retirement keeps the inventory truthful, evidences sanitized disposal, and prevents stale entries from distorting risk and compliance reporting.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To inflate the asset count</b>: the goal is accuracy, not inflating counts.</span><span class='qd'><b>To make the inventory harder to read</b>: clarity is a goal; obscurity is not.</span><span class='qd'><b>To increase license costs</b>: proper decommissioning typically reduces, not raises, license costs.</span>" },
{ id:"D2-050", domain:2, obj:"2.4", diff:"easy", q:"In modern data governance, which role is ACCOUNTABLE for the data and sets rules for its use, but typically does not perform the day-to-day technical protection?", options:["Data custodian","Data owner","Data processor","End user"], answer:1, explain:"<strong>Data owner</strong> — the owner is accountable for the data, defining classification, acceptable use, and access, while delegating hands-on protection to custodians.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Data custodian</b>: the custodian executes the technical protection the owner directs; it is not accountable in the governance sense.</span><span class='qd'><b>Data processor</b>: a processor handles data on a controller's behalf and does not set the rules.</span><span class='qd'><b>End user</b>: end users consume data under the owner's rules and hold no accountability for governance.</span>" },
{ id:"D2-051", domain:2, obj:"2.4", diff:"easy", q:"Which role is responsible for the hands-on, day-to-day protection of data, such as performing backups and applying access controls the owner specifies?", options:["Data owner","Data controller","Data custodian","Data subject"], answer:2, explain:"<strong>Data custodian</strong> — the custodian carries out the technical safeguards (backups, patching, access enforcement) according to the owner's requirements.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Data owner</b>: the owner sets requirements and is accountable but does not perform the daily technical work.</span><span class='qd'><b>Data controller</b>: a controller decides why and how personal data is processed, a privacy-law role, not a hands-on custodian.</span><span class='qd'><b>Data subject</b>: the data subject is the individual the personal data is about, not a protector of it.</span>" },
{ id:"D2-052", domain:2, obj:"2.4", diff:"medium", q:"Under GDPR, which entity determines the purposes and means of processing personal data?", options:["The data processor","The data subject","The supervisory authority","The data controller"], answer:3, explain:"<strong>The data controller</strong> — GDPR defines the controller as the party that decides why and how personal data is processed, bearing primary accountability for compliance.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The data processor</b>: the processor acts on the controller's instructions and does not set purposes and means.</span><span class='qd'><b>The data subject</b>: the data subject is the individual whose data is processed, not the decision-maker.</span><span class='qd'><b>The supervisory authority</b>: the supervisory authority regulates and enforces; it does not determine processing purposes.</span>" },
{ id:"D2-053", domain:2, obj:"2.4", diff:"medium", q:"A cloud provider stores and processes a client's customer data strictly according to the client's instructions. Under privacy law, the cloud provider is acting as which role?", options:["Data processor","Data controller","Data owner","Data subject"], answer:0, explain:"<strong>Data processor</strong> — processing personal data only on documented instructions from the client (the controller) makes the provider a data processor with defined but subordinate obligations.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Data controller</b>: the client, not the provider, decides purposes and means, so the client is the controller.</span><span class='qd'><b>Data owner</b>: 'owner' is an internal governance role, not the privacy-law term for the processing party here.</span><span class='qd'><b>Data subject</b>: the data subjects are the client's customers, not the provider.</span>" },
{ id:"D2-054", domain:2, obj:"2.4", diff:"easy", q:"Which term describes the identifiable individual whose personal data is being collected and processed?", options:["Data custodian","Data subject","Data owner","Data steward"], answer:1, explain:"<strong>Data subject</strong> — in privacy law the data subject is the living individual to whom the personal data relates and who holds rights over that data.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Data custodian</b>: a custodian protects data technically; it is not the individual described by the data.</span><span class='qd'><b>Data owner</b>: the owner is accountable for the data asset, not the person the data is about.</span><span class='qd'><b>Data steward</b>: a steward manages data quality and usage, not the individual the data concerns.</span>" },
{ id:"D2-055", domain:2, obj:"2.4", diff:"medium", q:"Which role focuses on ensuring data quality, consistent definitions, and appropriate business use of data across the organization?", options:["Data custodian","Data subject","Data steward","Data processor"], answer:2, explain:"<strong>Data steward</strong> — the steward is a business-facing role accountable for data quality, metadata, and fitness-for-use, complementing the owner and custodian.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Data custodian</b>: the custodian handles technical protection, not data-quality governance.</span><span class='qd'><b>Data subject</b>: the data subject is the individual described by personal data, not a governance role.</span><span class='qd'><b>Data processor</b>: a processor executes processing on instruction and is not responsible for enterprise data quality.</span>" },
{ id:"D2-056", domain:2, obj:"2.4", diff:"medium", q:"Order the data lifecycle phases correctly.", options:["Use, Create, Store, Destroy, Share, Archive","Destroy, Archive, Share, Use, Store, Create","Share, Use, Store, Create, Archive, Destroy","Create, Store, Use, Share, Archive, Destroy"], answer:3, explain:"<strong>Create, Store, Use, Share, Archive, Destroy</strong> — data is first created or collected, stored, used, shared as needed, archived when less active, and finally destroyed, with controls at each phase.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Use, Create, Store, Destroy, Share, Archive</b>: data cannot be used before it is created and stored.</span><span class='qd'><b>Destroy, Archive, Share, Use, Store, Create</b>: destruction cannot precede creation; the order is reversed.</span><span class='qd'><b>Share, Use, Store, Create, Archive, Destroy</b>: sharing and use cannot occur before creation and storage.</span>" },
{ id:"D2-057", domain:2, obj:"2.4", diff:"medium", q:"During which data lifecycle phase is media sanitization or cryptographic erasure MOST directly relevant?", options:["Destroy","Create","Store","Use"], answer:0, explain:"<strong>Destroy</strong> — the destruction phase is where sanitization, degaussing, shredding, or cryptographic erasure ensure data cannot be recovered from retired media.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Create</b>: creation concerns generating or collecting data, not destroying it.</span><span class='qd'><b>Store</b>: storage focuses on protecting data at rest, not eliminating it.</span><span class='qd'><b>Use</b>: the use phase concerns protecting data in use, not its final destruction.</span>" },
{ id:"D2-058", domain:2, obj:"2.4", diff:"hard", q:"A company appoints a business leader as data owner but assigns all technical safeguards to the IT operations team as custodians. A breach occurs due to a missed patch. Who remains ACCOUNTABLE for the data's protection?", options:["The IT operations team, because they missed the patch","The data owner, who is accountable even though custodians perform the work","The end users","No one, since it was a technical error"], answer:1, explain:"<strong>The data owner, who is accountable even though custodians perform the work</strong> — accountability for the data cannot be delegated; the owner remains answerable for its protection while custodians hold operational responsibility.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The IT operations team, because they missed the patch</b>: custodians are responsible for execution but do not hold ultimate accountability.</span><span class='qd'><b>The end users</b>: users follow handling rules and are not accountable for safeguarding the asset.</span><span class='qd'><b>No one, since it was a technical error</b>: accountability always rests with the owner regardless of cause.</span>" },
{ id:"D2-059", domain:2, obj:"2.4", diff:"medium", q:"Which of the following is the BEST reason to formally separate the owner, custodian, and processor roles?", options:["To create more job titles","To slow down data processing","To establish clear accountability, responsibility, and separation of duties over data","To avoid documenting anything"], answer:2, explain:"<strong>To establish clear accountability, responsibility, and separation of duties over data</strong> — distinct roles make it unambiguous who decides, who protects, and who processes, strengthening governance and reducing conflicts of interest.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To create more job titles</b>: the purpose is governance clarity, not title proliferation.</span><span class='qd'><b>To slow down data processing</b>: well-defined roles streamline, not hinder, processing.</span><span class='qd'><b>To avoid documenting anything</b>: role separation depends on documented responsibilities, not avoiding them.</span>" },
{ id:"D2-060", domain:2, obj:"2.4", diff:"easy", q:"What is the PRIMARY security concern during the 'Share' phase of the data lifecycle?", options:["Choosing a database engine","Buying more storage","Renaming the files","Ensuring data is disclosed only to authorized parties through secure channels"], answer:3, explain:"<strong>Ensuring data is disclosed only to authorized parties through secure channels</strong> — sharing multiplies exposure, so controls like access authorization, encryption in transit, and DLP govern who receives data and how.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Choosing a database engine</b>: engine choice is a storage/architecture concern, not the sharing risk.</span><span class='qd'><b>Buying more storage</b>: capacity is unrelated to controlling disclosure during sharing.</span><span class='qd'><b>Renaming the files</b>: renaming does not address authorized disclosure.</span>" },
{ id:"D2-061", domain:2, obj:"2.4", diff:"medium", q:"A data owner delegates day-to-day quality and metadata management to a data steward and technical protection to a custodian. Which responsibility does the owner RETAIN?", options:["Deciding data classification and acceptable use","Running nightly backups","Patching the servers","Encrypting the database files"], answer:0, explain:"<strong>Deciding data classification and acceptable use</strong> — setting classification, access, and acceptable-use policy is a core owner responsibility that is not delegated to stewards or custodians.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Running nightly backups</b>: backups are a custodian's operational task.</span><span class='qd'><b>Patching the servers</b>: patching is performed by custodians/operations, not owners.</span><span class='qd'><b>Encrypting the database files</b>: applying encryption is a custodial technical task carried out per owner requirements.</span>" },
{ id:"D2-062", domain:2, obj:"2.4", diff:"hard", q:"A controller engages a processor and the processor secretly subcontracts to another vendor without authorization. Which control BEST prevents this governance failure?", options:["Stronger passwords","A data processing agreement (DPA) that requires prior authorization for subprocessors","A faster network","More storage capacity"], answer:1, explain:"<strong>A data processing agreement (DPA) that requires prior authorization for subprocessors</strong> — a binding DPA obligates the processor to obtain approval before engaging subprocessors and imposes equivalent controls, preserving the controller's governance.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Stronger passwords</b>: passwords do not govern subprocessor engagement.</span><span class='qd'><b>A faster network</b>: network speed is irrelevant to contractual subprocessor control.</span><span class='qd'><b>More storage capacity</b>: capacity has no bearing on authorizing subprocessors.</span>" },
{ id:"D2-063", domain:2, obj:"2.4", diff:"medium", q:"Which data lifecycle phase is MOST concerned with protecting data in use, including preventing exposure in memory or on screen?", options:["Create","Archive","Use","Destroy"], answer:2, explain:"<strong>Use</strong> — the use phase addresses data actively processed in memory, displayed, or manipulated, where controls like memory protection, masking, and screen privacy apply.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Create</b>: creation is the origination of data, not its active processing.</span><span class='qd'><b>Archive</b>: archiving concerns long-term retention of inactive data.</span><span class='qd'><b>Destroy</b>: destruction is about eliminating data, not protecting it during processing.</span>" },
{ id:"D2-064", domain:2, obj:"2.4", diff:"easy", q:"Who is responsible for following the acceptable-use and handling rules set by the data owner when working with data?", options:["The data subject","The regulator","The auditor","The end user"], answer:3, explain:"<strong>The end user</strong> — end users must comply with the owner's acceptable-use and handling policies whenever they access or manipulate data.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The data subject</b>: the data subject is the individual the data is about, not necessarily an internal user of it.</span><span class='qd'><b>The regulator</b>: regulators enforce law; they do not follow the owner's internal handling rules.</span><span class='qd'><b>The auditor</b>: auditors assess compliance rather than being the primary handlers bound by acceptable-use rules.</span>" },
{ id:"D2-065", domain:2, obj:"2.4", diff:"medium", q:"An organization wants a single accountable person for a critical customer database. Which appointment BEST fits CISSP governance guidance?", options:["Designate a specific business data owner accountable for that database","Assign no owner and share responsibility informally","Let the whole company be collectively responsible","Assign ownership to an external auditor"], answer:0, explain:"<strong>Designate a specific business data owner accountable for that database</strong> — clear, singular ownership ensures someone is accountable for classification, access, and protection decisions for that asset.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Assign no owner and share responsibility informally</b>: diffuse responsibility means no one is truly accountable.</span><span class='qd'><b>Let the whole company be collectively responsible</b>: collective ownership dilutes accountability to the point of ineffectiveness.</span><span class='qd'><b>Assign ownership to an external auditor</b>: auditors must remain independent and cannot own the assets they may assess.</span>" },
{ id:"D2-066", domain:2, obj:"2.4", diff:"hard", q:"A privacy incident reveals that personal data was used for a new marketing purpose not covered by the original consent. Which role-based failure is MOST directly implicated?", options:["The custodian failed to back up data","The controller failed to ensure processing stayed within the lawful purpose","The end user typed too fast","The auditor scheduled the wrong meeting"], answer:1, explain:"<strong>The controller failed to ensure processing stayed within the lawful purpose</strong> — the controller determines and is accountable for the purposes of processing, so using data beyond the consented purpose is a controller governance failure.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The custodian failed to back up data</b>: backups are unrelated to purpose limitation.</span><span class='qd'><b>The end user typed too fast</b>: typing speed has nothing to do with lawful-purpose compliance.</span><span class='qd'><b>The auditor scheduled the wrong meeting</b>: scheduling is irrelevant to the processing-purpose breach.</span>" },
{ id:"D2-067", domain:2, obj:"2.4", diff:"medium", q:"In the data lifecycle, why is applying classification EARLY (at creation) considered a best practice?", options:["It makes files larger","It removes the need for owners","It ensures appropriate controls follow the data through every later phase","It prevents any sharing"], answer:2, explain:"<strong>It ensures appropriate controls follow the data through every later phase</strong> — classifying at creation lets storage, use, sharing, archival, and destruction controls be applied consistently based on sensitivity from the outset.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It makes files larger</b>: classification metadata is negligible and file size is not the point.</span><span class='qd'><b>It removes the need for owners</b>: classification is set by owners; it does not eliminate them.</span><span class='qd'><b>It prevents any sharing</b>: classification governs how data is shared, it does not forbid sharing.</span>" },
{ id:"D2-068", domain:2, obj:"2.4", diff:"medium", q:"Which statement BEST captures the relationship between a data owner and a data custodian?", options:["They are the same role","The custodian outranks the owner","The owner performs backups while the custodian sets policy","The owner sets requirements and is accountable; the custodian implements and maintains the controls"], answer:3, explain:"<strong>The owner sets requirements and is accountable; the custodian implements and maintains the controls</strong> — this division puts strategic accountability with the owner and operational responsibility with the custodian.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>They are the same role</b>: they are distinct roles with different authority and duties.</span><span class='qd'><b>The custodian outranks the owner</b>: the owner directs the custodian, not the reverse.</span><span class='qd'><b>The owner performs backups while the custodian sets policy</b>: this inverts the correct responsibilities.</span>" },
{ id:"D2-069", domain:2, obj:"2.4", diff:"easy", q:"Archiving data rather than deleting it during the lifecycle is MOST appropriate when which condition applies?", options:["The data is no longer actively used but must be retained for legal or business reasons","The data is worthless and must go immediately","The data is public marketing material","No one remembers what the data is"], answer:0, explain:"<strong>The data is no longer actively used but must be retained for legal or business reasons</strong> — archiving moves inactive but still-required data to cost-effective, protected storage until retention obligations end.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The data is worthless and must go immediately</b>: worthless data with no obligation should be destroyed, not archived.</span><span class='qd'><b>The data is public marketing material</b>: public material rarely needs protected archival for legal reasons.</span><span class='qd'><b>No one remembers what the data is</b>: unknown data should be identified and classified, not blindly archived.</span>" },
{ id:"D2-070", domain:2, obj:"2.6", diff:"medium", q:"An organization must decide who grants access to a sensitive HR dataset. In the governance model, who makes that authorization decision?", options:["The data custodian","The data owner (or their delegate) based on need-to-know","Any manager","The network team"], answer:1, explain:"<strong>The data owner (or their delegate) based on need-to-know</strong> — access authorization is an owner responsibility, granted according to business need-to-know, with custodians enforcing the decision technically.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The data custodian</b>: custodians implement access but do not decide who should be authorized.</span><span class='qd'><b>Any manager</b>: authority to grant access to a specific dataset rests with its owner, not arbitrary managers.</span><span class='qd'><b>The network team</b>: the network team supports connectivity, not data-access authorization decisions.</span>" },
{ id:"D2-071", domain:2, obj:"2.5", diff:"easy", q:"What is the PRIMARY purpose of a data retention policy?", options:["To keep all data forever","To make backups slower","To specify how long each type of data must be kept and when it must be securely disposed of","To increase storage costs deliberately"], answer:2, explain:"<strong>To specify how long each type of data must be kept and when it must be securely disposed of</strong> — a retention policy balances legal, regulatory, and business needs with the risk and cost of holding data too long.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To keep all data forever</b>: indefinite retention increases risk, cost, and liability and is rarely lawful or wise.</span><span class='qd'><b>To make backups slower</b>: retention policy governs lifespan, not backup speed.</span><span class='qd'><b>To increase storage costs deliberately</b>: retention aims to control, not inflate, storage costs.</span>" },
{ id:"D2-072", domain:2, obj:"2.5", diff:"medium", q:"A regulation requires certain financial records be kept for seven years. What is the PRIMARY risk of keeping them for twenty years instead?", options:["No risk at all","Improved compliance automatically","Faster e-discovery","Increased liability, cost, and exposure surface from retaining data longer than required"], answer:3, explain:"<strong>Increased liability, cost, and exposure surface from retaining data longer than required</strong> — over-retention expands the volume subject to breach, e-discovery, and privacy obligations while adding storage cost with no compliance benefit.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>No risk at all</b>: holding data far past requirement demonstrably raises risk and cost.</span><span class='qd'><b>Improved compliance automatically</b>: exceeding retention can actually violate data-minimization requirements.</span><span class='qd'><b>Faster e-discovery</b>: more retained data makes e-discovery slower and costlier, not faster.</span>" },
{ id:"D2-073", domain:2, obj:"2.5", diff:"medium", q:"A vendor announces that a critical firewall will reach end-of-support (EOS) next quarter. What is the PRIMARY security implication of continuing to run it past EOS?", options:["It will no longer receive security patches, leaving known vulnerabilities unfixed","It will run faster","It automatically becomes more secure","Its warranty extends indefinitely"], answer:0, explain:"<strong>It will no longer receive security patches, leaving known vulnerabilities unfixed</strong> — after EOS the vendor stops issuing fixes, so newly discovered flaws remain exploitable, making continued use a growing risk.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It will run faster</b>: EOS status does not improve performance.</span><span class='qd'><b>It automatically becomes more secure</b>: the opposite is true; it becomes progressively less secure.</span><span class='qd'><b>Its warranty extends indefinitely</b>: EOS typically ends support and warranty, not extends it.</span>" },
{ id:"D2-074", domain:2, obj:"2.5", diff:"easy", q:"What do the terms EOL and EOS most commonly denote for an asset?", options:["Encryption on load and encryption on save","End-of-life (no longer sold/produced) and end-of-support (no more updates)","Extra online and extra secure","Errors on log and errors on system"], answer:1, explain:"<strong>End-of-life (no longer sold/produced) and end-of-support (no more updates)</strong> — EOL marks when a product is retired from sale/production and EOS marks when the vendor ceases support and security updates.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Encryption on load and encryption on save</b>: these are invented expansions unrelated to lifecycle terms.</span><span class='qd'><b>Extra online and extra secure</b>: these are not real EOL/EOS meanings.</span><span class='qd'><b>Errors on log and errors on system</b>: these do not describe end-of-life or end-of-support.</span>" },
{ id:"D2-075", domain:2, obj:"2.5", diff:"medium", q:"Legal counsel issues a litigation hold on records that were scheduled for routine destruction. What must happen to those records?", options:["Destroy them on schedule anyway","Encrypt and then delete them","Suspend their destruction and preserve them until the hold is lifted","Share them publicly"], answer:2, explain:"<strong>Suspend their destruction and preserve them until the hold is lifted</strong> — a litigation hold overrides the normal retention schedule; destroying held records could constitute spoliation of evidence.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Destroy them on schedule anyway</b>: destroying data under hold is spoliation and can carry severe legal penalties.</span><span class='qd'><b>Encrypt and then delete them</b>: deletion in any form violates the hold's preservation requirement.</span><span class='qd'><b>Share them publicly</b>: public disclosure is unrelated and inappropriate for held records.</span>" },
{ id:"D2-076", domain:2, obj:"2.5", diff:"hard", q:"An organization's retention schedule conflicts: privacy law says delete personal data after 2 years, but industry regulation says keep transaction records for 5 years. What is the BEST approach?", options:["Ignore both rules","Always keep everything for 5 years","Always delete everything after 2 years","Analyze the specific data elements and apply the most appropriate lawful retention per element, minimizing personal data where possible"], answer:3, explain:"<strong>Analyze the specific data elements and apply the most appropriate lawful retention per element, minimizing personal data where possible</strong> — conflicts are resolved by examining what each rule covers, retaining required transaction data while minimizing or anonymizing personal elements to satisfy both.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Ignore both rules</b>: ignoring legal requirements invites penalties from both regimes.</span><span class='qd'><b>Always keep everything for 5 years</b>: retaining all personal data for 5 years may violate the 2-year privacy limit.</span><span class='qd'><b>Always delete everything after 2 years</b>: deleting transaction records at 2 years breaks the 5-year regulatory requirement.</span>" },
{ id:"D2-077", domain:2, obj:"2.5", diff:"medium", q:"Why is it important to include secure destruction requirements within a retention policy?", options:["To ensure data is not just kept for the right time but also disposed of so it cannot be recovered","To make the policy longer","To confuse employees","To avoid backups"], answer:0, explain:"<strong>To ensure data is not just kept for the right time but also disposed of so it cannot be recovered</strong> — retention and destruction are two sides of the same policy; specifying sanitization methods closes the lifecycle securely.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To make the policy longer</b>: length is not the purpose; secure end-of-life handling is.</span><span class='qd'><b>To confuse employees</b>: clear destruction rules reduce, not create, confusion.</span><span class='qd'><b>To avoid backups</b>: destruction requirements do not eliminate the need for backups during retention.</span>" },
{ id:"D2-078", domain:2, obj:"2.5", diff:"easy", q:"An application vendor moves a product to end-of-life. What is the BEST proactive step the asset owner should take?", options:["Do nothing until it breaks","Plan and execute migration or replacement before support ends","Disable all monitoring","Publicly post the credentials"], answer:1, explain:"<strong>Plan and execute migration or replacement before support ends</strong> — proactively migrating to a supported product avoids running unsupported, unpatched software and the risk that entails.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Do nothing until it breaks</b>: waiting for failure leaves the asset exposed and unsupported.</span><span class='qd'><b>Disable all monitoring</b>: reducing visibility on an aging asset increases, not decreases, risk.</span><span class='qd'><b>Publicly post the credentials</b>: exposing credentials is a severe security failure unrelated to EOL planning.</span>" },
{ id:"D2-079", domain:2, obj:"2.5", diff:"hard", q:"A business unit wants to retain marketing analytics 'indefinitely, just in case.' As the security manager, what is the BEST response aligned to data minimization?", options:["Agree and keep everything forever","Delete the analytics immediately","Push back and set a defensible retention period tied to a documented business or legal need","Move the data offsite and forget about it"], answer:2, explain:"<strong>Push back and set a defensible retention period tied to a documented business or legal need</strong> — data minimization requires retaining data only as long as a legitimate need exists; indefinite 'just in case' storage increases risk without justification.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Agree and keep everything forever</b>: indefinite retention contradicts data minimization and raises liability.</span><span class='qd'><b>Delete the analytics immediately</b>: abrupt deletion may destroy legitimately useful data without analysis.</span><span class='qd'><b>Move the data offsite and forget about it</b>: relocating unmanaged data still violates minimization and loses governance.</span>" },
{ id:"D2-080", domain:2, obj:"2.5", diff:"medium", q:"Which document typically records approved retention periods for each record category across the organization?", options:["A network diagram","A password list","A marketing brochure","A retention schedule"], answer:3, explain:"<strong>A retention schedule</strong> — the retention schedule enumerates record categories and their approved retention periods and disposition actions, operationalizing the retention policy.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A network diagram</b>: a diagram depicts topology, not record retention periods.</span><span class='qd'><b>A password list</b>: a password list is a credential store, unrelated to retention.</span><span class='qd'><b>A marketing brochure</b>: a brochure is promotional material, not a governance record.</span>" },
{ id:"D2-081", domain:2, obj:"2.5", diff:"medium", q:"Running unsupported (past-EOS) operating systems in a regulated environment MOST directly creates which compliance concern?", options:["Failure to meet requirements for supported, patchable systems, risking findings and penalties","Improved audit scores","Automatic certification","Reduced attack surface"], answer:0, explain:"<strong>Failure to meet requirements for supported, patchable systems, risking findings and penalties</strong> — many frameworks require systems be under vendor support so they can be patched; unsupported systems commonly generate audit findings.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Improved audit scores</b>: unsupported systems lower, not raise, audit outcomes.</span><span class='qd'><b>Automatic certification</b>: EOS systems jeopardize certification rather than granting it.</span><span class='qd'><b>Reduced attack surface</b>: unpatched EOS systems increase exposure.</span>" },
{ id:"D2-082", domain:2, obj:"2.5", diff:"easy", q:"What is the relationship between data retention and data destruction?", options:["They are unrelated","Retention defines how long to keep data; destruction is the secure disposal once retention ends","Destruction always precedes retention","Retention means never destroying data"], answer:1, explain:"<strong>Retention defines how long to keep data; destruction is the secure disposal once retention ends</strong> — the two are sequential stages: keep for the required period, then dispose of securely.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>They are unrelated</b>: they are directly linked phases of the same lifecycle policy.</span><span class='qd'><b>Destruction always precedes retention</b>: you cannot destroy data before its retention period elapses.</span><span class='qd'><b>Retention means never destroying data</b>: retention includes a defined end after which destruction occurs.</span>" },
{ id:"D2-083", domain:2, obj:"2.5", diff:"hard", q:"A hardware appliance is EOL but still functions; the vendor offers paid extended support for two more years. As the risk owner, what is the BEST decision framework?", options:["Always keep it, cost is irrelevant","Immediately discard it regardless of impact","Weigh the risk of unsupported operation against the cost of extended support versus timely replacement","Ignore the EOL notice"], answer:2, explain:"<strong>Weigh the risk of unsupported operation against the cost of extended support versus timely replacement</strong> — a risk-based cost/benefit analysis, comparing extended support, replacement, and residual risk, drives the sound managerial decision.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Always keep it, cost is irrelevant</b>: cost and risk are central to a defensible decision.</span><span class='qd'><b>Immediately discard it regardless of impact</b>: abrupt disposal ignoring business impact is not risk-based.</span><span class='qd'><b>Ignore the EOL notice</b>: ignoring EOL leaves the risk unmanaged and undocumented.</span>" },
{ id:"D2-084", domain:2, obj:"2.5", diff:"medium", q:"A company keeps customer emails only as long as needed for the service and then deletes them. Which privacy principle does this BEST embody?", options:["Data maximization","Indefinite retention","Unlimited sharing","Storage limitation / retention minimization"], answer:3, explain:"<strong>Storage limitation / retention minimization</strong> — keeping personal data only as long as necessary for the stated purpose is the storage-limitation principle central to modern privacy law.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Data maximization</b>: privacy law favors minimization, not maximizing data held.</span><span class='qd'><b>Indefinite retention</b>: indefinite retention is the opposite of storage limitation.</span><span class='qd'><b>Unlimited sharing</b>: sharing scope is a different principle unrelated to retention duration.</span>" },
{ id:"D2-085", domain:2, obj:"2.6", diff:"easy", q:"Which of the following BEST lists the three states of data that require protection?", options:["At rest, in transit, in use","Hot, warm, cold","Public, private, secret","Raw, refined, archived"], answer:0, explain:"<strong>At rest, in transit, in use</strong> — data must be protected while stored (at rest), while moving across networks (in transit), and while being processed (in use), each with distinct controls.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Hot, warm, cold</b>: these describe storage tiers or DR site readiness, not data states.</span><span class='qd'><b>Public, private, secret</b>: these are classification levels, not states of data.</span><span class='qd'><b>Raw, refined, archived</b>: these describe processing stages, not the security states of data.</span>" },
{ id:"D2-086", domain:2, obj:"2.6", diff:"medium", q:"Which control MOST directly protects data at rest on a stolen laptop's disk?", options:["TLS","Full-disk encryption","A firewall rule","A load balancer"], answer:1, explain:"<strong>Full-disk encryption</strong> — encrypting the disk renders stored data unreadable without the key, protecting data at rest if the device is lost or stolen.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>TLS</b>: TLS protects data in transit over the network, not data at rest on the disk.</span><span class='qd'><b>A firewall rule</b>: a firewall controls network traffic and cannot protect a stolen physical disk.</span><span class='qd'><b>A load balancer</b>: a load balancer distributes traffic and has no role in protecting stored data.</span>" },
{ id:"D2-087", domain:2, obj:"2.6", diff:"medium", q:"Which technology is designed to detect and prevent sensitive data from leaving the organization through email, web uploads, or removable media?", options:["A DNS resolver","A hypervisor","Data loss prevention (DLP)","A load balancer"], answer:2, explain:"<strong>Data loss prevention (DLP)</strong> — DLP inspects content and context to detect and block unauthorized exfiltration of sensitive data across endpoints, network, and cloud channels.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A DNS resolver</b>: a resolver translates names to addresses and does not inspect data for leakage.</span><span class='qd'><b>A hypervisor</b>: a hypervisor runs virtual machines and is not a data-exfiltration control.</span><span class='qd'><b>A load balancer</b>: a load balancer spreads traffic and does not prevent data loss.</span>" },
{ id:"D2-088", domain:2, obj:"2.6", diff:"medium", q:"A media company wants to control what recipients can do with distributed content, such as preventing copying, printing, or forwarding after delivery. Which technology BEST fits?", options:["A VPN","A firewall","RAID","Digital rights management (DRM)"], answer:3, explain:"<strong>Digital rights management (DRM)</strong> — DRM enforces persistent usage restrictions (view, copy, print, forward, expire) on content even after it leaves the sender's control.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A VPN</b>: a VPN secures a network channel but cannot restrict what a recipient does with delivered content.</span><span class='qd'><b>A firewall</b>: a firewall filters traffic and does not govern post-delivery usage rights.</span><span class='qd'><b>RAID</b>: RAID provides disk redundancy, unrelated to content usage control.</span>" },
{ id:"D2-089", domain:2, obj:"2.6", diff:"medium", q:"An organization wants visibility and policy enforcement over data moving to and within multiple SaaS cloud applications. Which control is PURPOSE-BUILT for this?", options:["A cloud access security broker (CASB)","A local antivirus scanner","A cable modem","A punch-down block"], answer:0, explain:"<strong>A cloud access security broker (CASB)</strong> — a CASB sits between users and cloud services to provide visibility, DLP, access control, and threat protection across SaaS usage.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A local antivirus scanner</b>: endpoint AV inspects files locally and does not broker cloud service policy.</span><span class='qd'><b>A cable modem</b>: a modem provides connectivity, not cloud data governance.</span><span class='qd'><b>A punch-down block</b>: a punch-down block is physical cabling hardware, irrelevant to cloud policy.</span>" },
{ id:"D2-090", domain:2, obj:"2.6", diff:"hard", q:"A security manager adopts NIST SP 800-53 as a baseline but must remove controls that do not apply to a system with no wireless capability. This process of adjusting the baseline to the environment is called what?", options:["Aggregation","Scoping","Steganography","Normalization"], answer:1, explain:"<strong>Scoping</strong> — scoping removes or marks not-applicable baseline controls (such as wireless controls on a wired-only system) so the baseline fits the actual environment.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Aggregation</b>: aggregation concerns combined sensitivity of data, not adjusting a control baseline.</span><span class='qd'><b>Steganography</b>: steganography hides data within other data, unrelated to control selection.</span><span class='qd'><b>Normalization</b>: normalization is a database design technique, not baseline adjustment.</span>" },
{ id:"D2-091", domain:2, obj:"2.6", diff:"hard", q:"After scoping, the manager strengthens some controls and adds compensating ones to address organization-specific risks and threats. This refinement of the baseline is called what?", options:["Degaussing","Sharding","Tailoring","Tokenization"], answer:2, explain:"<strong>Tailoring</strong> — tailoring refines a scoped baseline by adjusting, adding, or strengthening controls to align with the organization's specific risk, threat, and operational context.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Degaussing</b>: degaussing sanitizes magnetic media and is unrelated to control selection.</span><span class='qd'><b>Sharding</b>: sharding partitions databases for scale, not a control-baseline activity.</span><span class='qd'><b>Tokenization</b>: tokenization substitutes sensitive values with tokens; it is a data-protection technique, not baseline refinement.</span>" },
{ id:"D2-092", domain:2, obj:"2.6", diff:"medium", q:"Which control BEST protects data in transit between a web browser and a server?", options:["Full-disk encryption","Physical door locks","A retention schedule","TLS (Transport Layer Security)"], answer:3, explain:"<strong>TLS (Transport Layer Security)</strong> — TLS encrypts and authenticates data moving across the network, protecting confidentiality and integrity of data in transit.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Full-disk encryption</b>: FDE protects data at rest on a disk, not data crossing the network.</span><span class='qd'><b>Physical door locks</b>: locks are physical controls unrelated to network transmission.</span><span class='qd'><b>A retention schedule</b>: a retention schedule governs data lifespan, not in-transit protection.</span>" },
{ id:"D2-093", domain:2, obj:"2.6", diff:"easy", q:"Which technique replaces sensitive values (such as a credit card number) with a non-sensitive surrogate that has no exploitable meaning, while preserving format?", options:["Tokenization","Compression","Indexing","Replication"], answer:0, explain:"<strong>Tokenization</strong> — tokenization swaps a sensitive value for a format-preserving token, with the real value held in a secure vault, reducing exposure in downstream systems.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Compression</b>: compression reduces size but leaves the underlying sensitive data recoverable.</span><span class='qd'><b>Indexing</b>: indexing speeds lookups and does not conceal sensitive values.</span><span class='qd'><b>Replication</b>: replication copies data and increases, not reduces, exposure.</span>" },
{ id:"D2-094", domain:2, obj:"2.6", diff:"medium", q:"A report must show partial account numbers as ****1234 to support staff. Which data-protection technique is this?", options:["Full-disk encryption","Data masking","Load balancing","Steganography"], answer:1, explain:"<strong>Data masking</strong> — masking obscures parts of a value (showing only the last four digits) so users see enough to work while the full sensitive value stays hidden.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Full-disk encryption</b>: FDE protects stored data at rest and does not selectively display partial values.</span><span class='qd'><b>Load balancing</b>: load balancing distributes traffic and has nothing to do with hiding field values.</span><span class='qd'><b>Steganography</b>: steganography hides data inside other data, not partial display masking.</span>" },
{ id:"D2-095", domain:2, obj:"2.6", diff:"hard", q:"A security architect must choose between anonymization and pseudonymization for a dataset that analysts still need to re-link to individuals under strict control. Which is appropriate and why?", options:["Anonymization, because it is reversible","Anonymization, because it allows re-linking anytime","Pseudonymization, because it replaces identifiers with tokens that can be re-linked under controlled conditions","Neither can protect identity"], answer:2, explain:"<strong>Pseudonymization, because it replaces identifiers with tokens that can be re-linked under controlled conditions</strong> — pseudonymization preserves the ability to re-associate data with individuals via a protected key, unlike true anonymization which is irreversible.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Anonymization, because it is reversible</b>: proper anonymization is irreversible, contradicting the need to re-link.</span><span class='qd'><b>Anonymization, because it allows re-linking anytime</b>: anonymized data by definition cannot be re-linked to individuals.</span><span class='qd'><b>Neither can protect identity</b>: both techniques protect identity; the choice depends on whether re-linking is required.</span>" },
{ id:"D2-096", domain:2, obj:"2.6", diff:"medium", q:"Which reference is MOST commonly used as a source of security control baselines that organizations then scope and tailor?", options:["A vendor price list","A social media feed","A weather report","NIST SP 800-53 control catalog"], answer:3, explain:"<strong>NIST SP 800-53 control catalog</strong> — SP 800-53 provides a comprehensive catalog of security and privacy controls and baselines that organizations scope and tailor to their systems.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A vendor price list</b>: a price list contains costs, not security controls.</span><span class='qd'><b>A social media feed</b>: social media is not an authoritative control baseline.</span><span class='qd'><b>A weather report</b>: weather data is irrelevant to security control selection.</span>" },
{ id:"D2-097", domain:2, obj:"2.6", diff:"medium", q:"A DLP tool blocks an employee from copying a customer list to a USB drive. In which data state and channel is this control acting?", options:["Data in use, at the endpoint","Data at rest, in cold storage","Data in transit, over the WAN","No data state applies"], answer:0, explain:"<strong>Data in use, at the endpoint</strong> — the copy action occurs while the user is actively working with the data on the endpoint, so endpoint DLP intercepts the data-in-use operation to removable media.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Data at rest, in cold storage</b>: the data is being actively handled, not sitting idle in storage.</span><span class='qd'><b>Data in transit, over the WAN</b>: copying to local USB is a local endpoint action, not WAN transmission.</span><span class='qd'><b>No data state applies</b>: the operation clearly involves data in use at the endpoint.</span>" },
{ id:"D2-098", domain:2, obj:"2.6", diff:"hard", q:"A control baseline includes a requirement that is technically impossible on a legacy system. The organization implements a compensating control and documents an approved exception. Which baseline-adjustment concept does this illustrate?", options:["Aggregation","Tailoring with a compensating control","Remanence","Steganography"], answer:1, explain:"<strong>Tailoring with a compensating control</strong> — when a baseline control cannot be met directly, tailoring allows substituting an approved compensating control and documenting the exception to maintain equivalent protection.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Aggregation</b>: aggregation concerns combined data sensitivity, not substituting controls.</span><span class='qd'><b>Remanence</b>: remanence is residual data on media, unrelated to control substitution.</span><span class='qd'><b>Steganography</b>: steganography hides data and has nothing to do with baseline compensating controls.</span>" },
{ id:"D2-099", domain:2, obj:"2.6", diff:"easy", q:"Which pairing of data state and its MOST typical protective control is correct?", options:["Data in transit protected by full-disk encryption","Data at rest protected by TLS","Data in transit protected by TLS/VPN encryption","Data in use protected by shredding paper"], answer:2, explain:"<strong>Data in transit protected by TLS/VPN encryption</strong> — encrypting the communication channel with TLS or a VPN is the standard control for protecting data while it moves across networks.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Data in transit protected by full-disk encryption</b>: FDE protects data at rest, not moving data.</span><span class='qd'><b>Data at rest protected by TLS</b>: TLS protects data in transit, not stored data at rest.</span><span class='qd'><b>Data in use protected by shredding paper</b>: shredding is a destruction control, not a data-in-use protection.</span>" },
{ id:"D2-100", domain:2, obj:"2.6", diff:"hard", q:"A CISO is designing a layered data-protection strategy. Which combination BEST covers all three data states?", options:["Full-disk encryption only","TLS only","Physical locks for everything","Full-disk encryption for at rest, TLS/VPN for in transit, and DLP with access controls for in use"], answer:3, explain:"<strong>Full-disk encryption for at rest, TLS/VPN for in transit, and DLP with access controls for in use</strong> — a defense-in-depth strategy pairs the right control to each state, protecting stored, moving, and actively processed data together.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Full-disk encryption only</b>: FDE covers data at rest but leaves in-transit and in-use data unprotected.</span><span class='qd'><b>TLS only</b>: TLS covers data in transit but not at rest or in use.</span><span class='qd'><b>Physical locks for everything</b>: physical locks alone cannot protect data across network transit or active processing.</span>" }
);
